-- 6. Tonbridge × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'tonbridge',
  'Tonbridge has an active online community that increasingly shapes purchasing decisions. Local Facebook groups, Instagram discovery, and LinkedIn professional networks all influence which businesses get chosen. A family searching for a weekend activity checks The Angel Centre''s Instagram. A homeowner looking for a tradesperson asks for recommendations in a Tonbridge Facebook group. A professional seeking an accountant reviews LinkedIn profiles before making contact. Yet many Tonbridge businesses have social media presences that were set up hastily, have not been updated in months, or present an inconsistent image that undermines rather than builds trust. We set up and optimise social media profiles for Tonbridge businesses that look professional, appear in the right conversations, and convert social browsers into paying customers.',
  'Tonbridge''s social media landscape is shaped by its mixed demographic. Facebook community groups are active with recommendation requests and local discussion, particularly among families. Instagram serves the hospitality, retail, and activity sectors, with Tonbridge Castle and the River Medway providing photogenic backdrops. LinkedIn connects the professional services sector with the commuter demographic. The Angel Centre and local events provide regular content hooks. The Tonbridge and Malling context means nearby communities also participate in Tonbridge social media conversations.',
  'Social media quality among Tonbridge businesses is varied. Some hospitality and activity businesses maintain strong presences, while many professional services and trades have minimal or outdated profiles. The active community group culture means businesses with professional social presences get recommended and tagged, while those without are invisible in these crucial word-of-mouth channels.',
  'Our social media setup for Tonbridge identifies the platforms that drive business for your specific sector. Facebook for community engagement and recommendation visibility. Instagram for visual businesses leveraging the Castle and Medway backdrop. LinkedIn for professional services targeting the commuter demographic. Each platform is set up with professional imagery, consistent branding, and a content framework that maintains quality after our handover.',
  '{"population": 39000, "borough": "Tonbridge and Malling", "business_districts": ["High Street", "Castle area", "Hadlow Road", "Quarry Hill area"], "key_fact": "Active community groups and diverse demographics create platform-specific social media opportunities"}',
  '[{"title": "Invisible in Tonbridge community group recommendations", "description": "When a Tonbridge resident asks for a plumber recommendation in a Facebook group, the businesses that get tagged are those with professional, active profiles. If your page is outdated or nonexistent, you are excluded from the most powerful word-of-mouth channel in the town."}, {"title": "Outdated social profiles undermining Tonbridge business trust", "description": "A prospect checks your Facebook or Instagram after hearing about your business. They find a blurry profile picture, last post from six months ago, and outdated opening hours. Trust evaporates. They choose the competitor whose social presence looks current and professional."}, {"title": "Wrong platform focus wasting Tonbridge marketing effort", "description": "A professional service firm posting daily on Instagram while neglecting LinkedIn misses the commuter audience entirely. A trade business investing in TikTok while ignoring Facebook community groups loses the recommendation channel that generates actual work. Platform selection matters as much as content quality."}]',
  '[{"title": "Platform-specific setup for Tonbridge market segments", "description": "We identify which platforms matter for your specific Tonbridge audience and set up each one professionally. Facebook for community visibility and recommendations. Instagram for visual businesses with Castle and Medway content hooks. LinkedIn for professional services targeting commuter professionals. Every platform optimised for its intended audience."}, {"title": "Professional visual identity across Tonbridge social profiles", "description": "Consistent, high-quality cover images, profile photos, and branded templates across every platform. Your social presence reflects the same professional quality as your High Street signage and website. Tonbridge customers encounter a cohesive, trustworthy brand image wherever they find you."}, {"title": "Content framework using Tonbridge events and local hooks", "description": "A practical content calendar using Tonbridge Castle events, River Medway seasonal changes, Angel Centre activities, and borough-wide happenings as content hooks. Your team can maintain engaging, locally relevant social media independently using the framework and templates we provide."}]',
  '[{"question": "Which social platforms matter most for Tonbridge businesses?", "answer": "Facebook is essential for most Tonbridge businesses due to active community groups. LinkedIn is critical for professional services targeting the commuter demographic. Instagram works well for hospitality, retail, and activity businesses. We recommend the right mix based on your specific Tonbridge audience."}, {"question": "Can you help me get noticed in Tonbridge Facebook groups?", "answer": "We set up your profile to make a strong impression when you are tagged or mentioned in community groups. Professional imagery, complete information, and active posting history all contribute to credibility in group recommendations. We also provide guidelines for authentic community group engagement."}, {"question": "How long does social media setup take?", "answer": "A complete multi-platform setup typically takes one to two weeks. This includes platform strategy, professional visual asset creation, profile optimisation with accurate business information, and development of a content framework with templates for ongoing management."}, {"question": "Do you provide ongoing social media management?", "answer": "Our core service is professional setup and strategy. We deliver optimised profiles with content frameworks that your team can execute independently. Ongoing management retainers are available if needed, but many Tonbridge businesses find the framework and templates sufficient to maintain quality."}]',
  'trust'
)
